// Circuit Poem — Energy Grid
// Adapted from GenerativeArtGallery / artwork7

let cpGrid = [];
let cpCols = 10;
let cpRows = 10;
let cpPrevDens = '';

let cpPalettes = {
  cyberpunk: { bg: [240, 80, 8],  node: [300, 80, 80], energy: [200, 90, 100], wire: [280, 60, 60] },
  pastel:    { bg: [200, 14, 92], node: [200, 48, 78], energy: [40,  68, 95],  wire: [180, 28, 68] },
  warm:      { bg: [25,  38, 12], node: [30,  68, 78], energy: [50,  88, 100], wire: [20,  48, 58] },
  cool:      { bg: [205, 58, 10], node: [190, 68, 74], energy: [160, 80, 95],  wire: [210, 48, 52] },
  mono:      { bg: [0,   0,  7],  node: [0,   0,  68], energy: [0,   0,  100], wire: [0,   0,  38] }
};

function cpBuild(cs) {
  cpCols = Math.floor(400 / cs);
  cpRows = Math.floor(400 / cs);
  let grid = [];
  for (let i = 0; i < cpCols; i++) {
    grid[i] = [];
    for (let j = 0; j < cpRows; j++) {
      let roll = Math.random();
      grid[i][j] = {
        energy: 0,
        type: roll < 0.12 ? 'power' : roll < 0.22 ? 'relay' : 'node'
      };
    }
  }
  return grid;
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
  cpGrid = cpBuild(40);
};

p.draw = function() {
  let palStr   = p.getSynthVar('color_palette') || 'cyberpunk';
  let densStr  = p.getSynthVar('grid_density') || 'medium';
  let rateStr  = p.getSynthVar('energy_rate') || 'medium';
  let glowStr  = p.getSynthVar('glow_style') || 'soft';

  let cs = densStr === 'coarse' ? 60 : densStr === 'medium' ? 40 : 28;
  if (densStr !== cpPrevDens) { cpGrid = cpBuild(cs); cpPrevDens = densStr; }

  let spawnChance = rateStr === 'low' ? 0.01 : rateStr === 'medium' ? 0.045 : 0.11;
  let decay       = rateStr === 'low' ? 0.91 : rateStr === 'medium' ? 0.94 : 0.97;
  let pal         = cpPalettes[palStr] || cpPalettes.cyberpunk;

  p.background(pal.bg[0], pal.bg[1], pal.bg[2], 100);

  // Propagate energy into a new buffer
  let next = [];
  for (let i = 0; i < cpCols; i++) {
    next[i] = [];
    for (let j = 0; j < cpRows; j++) next[i][j] = cpGrid[i][j].energy * decay;
  }
  for (let i = 0; i < cpCols; i++) {
    for (let j = 0; j < cpRows; j++) {
      let e = cpGrid[i][j].energy;
      if (e > 0.05) {
        let spread = cpGrid[i][j].type === 'relay' ? 0.72 : 0.62;
        let dirs = [[1,0],[-1,0],[0,1],[0,-1]];
        dirs.forEach(function(d) {
          let ni = i + d[0], nj = j + d[1];
          if (ni >= 0 && ni < cpCols && nj >= 0 && nj < cpRows) {
            next[ni][nj] = Math.max(next[ni][nj], e * spread);
          }
        });
      }
    }
  }
  if (Math.random() < spawnChance) {
    let si = Math.floor(Math.random() * cpCols);
    let sj = Math.floor(Math.random() * cpRows);
    next[si][sj] = 1;
  }
  for (let i = 0; i < cpCols; i++) for (let j = 0; j < cpRows; j++) cpGrid[i][j].energy = next[i][j];

  // Draw wires
  for (let i = 0; i < cpCols; i++) {
    for (let j = 0; j < cpRows; j++) {
      let x = i * cs + cs / 2, y = j * cs + cs / 2;
      let e = cpGrid[i][j].energy;
      if (i < cpCols - 1) {
        let we = Math.max(e, cpGrid[i+1][j].energy);
        if (we > 0.04) {
          p.stroke(pal.wire[0], pal.wire[1], pal.wire[2], p.map(we, 0, 1, 5, 62));
          p.strokeWeight(we * 2.2);
          p.line(x, y, x + cs, y);
        }
      }
      if (j < cpRows - 1) {
        let we = Math.max(e, cpGrid[i][j+1].energy);
        if (we > 0.04) {
          p.stroke(pal.wire[0], pal.wire[1], pal.wire[2], p.map(we, 0, 1, 5, 62));
          p.strokeWeight(we * 2.2);
          p.line(x, y, x, y + cs);
        }
      }
    }
  }

  // Draw nodes
  for (let i = 0; i < cpCols; i++) {
    for (let j = 0; j < cpRows; j++) {
      let x = i * cs + cs / 2, y = j * cs + cs / 2;
      let e    = cpGrid[i][j].energy;
      let type = cpGrid[i][j].type;
      let ns   = type === 'power' ? cs * 0.34 : type === 'relay' ? cs * 0.2 : cs * 0.13;

      // Glow
      if (e > 0.08 && glowStr !== 'none') {
        let glowR = ns * (glowStr === 'intense' ? 5 : 3) * e;
        p.noStroke();
        p.fill(pal.energy[0], pal.energy[1], pal.energy[2], e * (glowStr === 'intense' ? 35 : 20));
        p.ellipse(x, y, glowR * 2, glowR * 2);
      }

      p.noStroke();
      if (e > 0.04) {
        p.fill(pal.energy[0], pal.energy[1], p.map(e, 0, 1, 42, 96), p.map(e, 0, 1, 18, 96));
      } else {
        p.fill(pal.node[0], pal.node[1], pal.node[2], 48);
      }

      if (type === 'power') {
        p.rect(x - ns / 2, y - ns / 2, ns, ns, 2);
      } else if (type === 'relay') {
        p.push(); p.translate(x, y); p.rotate(p.PI / 4);
        p.rect(-ns / 2, -ns / 2, ns, ns, 1);
        p.pop();
      } else {
        p.ellipse(x, y, ns * 2, ns * 2);
      }
    }
  }
};
